import { Component } from '@angular/core';

@Component({
  selector: 'app-navbar',
  templateUrl: './navbar.component.html',
  styleUrls: ['./navbar.component.scss']
})
export class NavbarComponent {
  isOpen = false;

  links = [
    { path: '/', label: 'Home' },
    { path: '/about', label: 'About' },
    { path: '/projects', label: 'Projects' },
    { path: '/achievements', label: 'Achievements' },
    { path: '/research', label: 'Research' },
    { path: '/certifications', label: 'Certifications' },
    { path: '/cv', label: 'CV' },
    { path: '/contact', label: 'Contact' }
  ];

  toggle() { this.isOpen = !this.isOpen; }
  close() { this.isOpen = false; }
}
<nav class="navbar">
  <div class="container navbar__inner">
    <a routerLink="/" class="navbar__brand" (click)="close()">
      <span class="navbar__prompt">joyce&#64;security:~$</span>
    </a>

    <button class="navbar__toggle" (click)="toggle()" aria-label="Toggle navigation menu">
      <span></span><span></span><span></span>
    </button>

    <ul class="navbar__links" [class.navbar__links--open]="isOpen">
      <li *ngFor="let link of links">
        <a [routerLink]="link.path" routerLinkActive="active" [routerLinkActiveOptions]="{exact: link.path === '/'}" (click)="close()">
          {{ link.label }}
        </a>
      </li>
    </ul>
  </div>
</nav>
